import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { useAuthStore } from '@/store/authStore';

export default function CheckIn() {
  const { user } = useAuthStore();
  const [checkedIn, setCheckedIn] = useState(false);
  const [checkInTime, setCheckInTime] = useState<string | null>(null);
  const [checkOutTime, setCheckOutTime] = useState<string | null>(null);
  const [location, setLocation] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // Get user's current location
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          setLocation(`${latitude}, ${longitude}`);
        },
        (error) => {
          console.error('Geolocation error:', error);
        }
      );
    }
  }, []);

  const handleCheckIn = async () => {
    try {
      setLoading(true);
      const time = new Date().toLocaleTimeString();
      setCheckInTime(time);
      setCheckedIn(true);
      // TODO: Send to API
    } finally {
      setLoading(false);
    }
  };

  const handleCheckOut = async () => {
    try {
      setLoading(true);
      const time = new Date().toLocaleTimeString();
      setCheckOutTime(time);
      // TODO: Send to API
      alert('Check out successful');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-6 max-w-md mx-auto space-y-6">
      <div className="text-center">
        <h1 className="text-3xl font-bold">Check In/Out</h1>
        <p className="text-gray-600 mt-2">Welcome, {user?.firstName} {user?.lastName}</p>
      </div>

      <div className="bg-blue-50 p-4 rounded-lg text-center">
        <p className="text-sm text-gray-600">Current Time</p>
        <p className="text-3xl font-bold text-blue-600">
          {new Date().toLocaleTimeString()}
        </p>
      </div>

      {location && (
        <Alert>
          <AlertDescription>
            Location: {location}
          </AlertDescription>
        </Alert>
      )}

      {checkedIn && (
        <div className="bg-green-50 p-4 rounded-lg text-center">
          <p className="text-sm text-gray-600">Checked In At</p>
          <p className="text-2xl font-bold text-green-600">{checkInTime}</p>
        </div>
      )}

      {checkOutTime && (
        <div className="bg-orange-50 p-4 rounded-lg text-center">
          <p className="text-sm text-gray-600">Checked Out At</p>
          <p className="text-2xl font-bold text-orange-600">{checkOutTime}</p>
        </div>
      )}

      <div className="space-y-2">
        {!checkedIn ? (
          <Button onClick={handleCheckIn} className="w-full" disabled={loading} size="lg">
            {loading ? 'Checking In...' : 'Check In'}
          </Button>
        ) : !checkOutTime ? (
          <Button onClick={handleCheckOut} className="w-full" disabled={loading} size="lg" variant="destructive">
            {loading ? 'Checking Out...' : 'Check Out'}
          </Button>
        ) : (
          <Alert className="border-green-200 bg-green-50">
            <AlertDescription className="text-green-800">
              You have completed your attendance for today
            </AlertDescription>
          </Alert>
        )}
      </div>
    </div>
  );
}
